#include <omp.h>
#include <stdio.h>
#include <stdlib.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_diagonal(float *m, int matrix_dim, int offset) {
    float shadow[BLOCK_SIZE * BLOCK_SIZE];
    int i, j;
    int tx;

    // Load diagonal block into shadow
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int array_offset = offset * matrix_dim + offset + tx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset];
            array_offset += matrix_dim;
        }
    }

    // Barrier equivalent: single thread modifies shadow in stages with synchronization
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for private(j) schedule(static)
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if (tx > i) {
                for (j = 0; j < i; j++)
                    shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }
        }
        #pragma omp barrier

        #pragma omp parallel for private(j) schedule(static)
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if (tx > i) {
                for (j = 0; j < i + 1; j++)
                    shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
        }
        #pragma omp barrier
    }

    // Write back to global memory
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            array_offset += matrix_dim;
        }
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset) {
    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];
    int i, j, idx;

    int bx = 0; // In OpenMP version, bx corresponds to index in loop

    // Load data into dia, peri_row, peri_col
    #pragma omp parallel for private(i, idx) schedule(static)
    for (int tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
        if (tx < BLOCK_SIZE) {
            idx = tx;
            int array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE / 2; i++) {
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
                array_offset += matrix_dim;
            }
        } else {
            idx = tx - BLOCK_SIZE;
            int array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
            for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }
            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }
        }
    }

    #pragma omp barrier

    // Compute peri_row and peri_col
    #pragma omp parallel for private(i, j, idx) schedule(static)
    for (int tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
        if (tx < BLOCK_SIZE) {
            idx = tx;
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (j = 0; j < i; j++)
                    peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
            }
        } else {
            idx = tx - BLOCK_SIZE;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < i; j++)
                    peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
            }
        }
    }

    #pragma omp barrier

    // Write back to global memory
    #pragma omp parallel for private(i, idx) schedule(static)
    for (int tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
        if (tx < BLOCK_SIZE) {
            idx = tx;
            int array_offset = (offset + 1) * matrix_dim + offset;
            for (i = 1; i < BLOCK_SIZE; i++) {
                m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = peri_row[i * BLOCK_SIZE + idx];
                array_offset += matrix_dim;
            }
        } else {
            idx = tx - BLOCK_SIZE;
            int array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                array_offset += matrix_dim;
            }
        }
    }
}

void lud_internal(float *m, int matrix_dim, int offset, int bx, int by) {
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];
    int tx, ty, i;
    float sum;

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    // Load peri_row and peri_col from global memory
    #pragma omp parallel for collapse(2) private(tx, ty) schedule(static)
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
            peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
        }
    }

    #pragma omp barrier

    // Compute sum and update m
    #pragma omp parallel for collapse(2) private(i, sum) schedule(static)
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            sum = 0.0f;
            for (i = 0; i < BLOCK_SIZE; i++)
                sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
            m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i, j, k;

    int num_blocks = matrix_dim / BLOCK_SIZE;

    for (i = 0; i < matrix_dim; i += BLOCK_SIZE) {
        int offset = i;

        // 1. lud_diagonal for current block
        lud_diagonal(m, matrix_dim, offset);

        int blocks_left = (matrix_dim - i) / BLOCK_SIZE - 1;

        if (blocks_left > 0) {
            // 2. lud_perimeter for all blocks in the perimeter
            #pragma omp parallel for schedule(static)
            for (j = 0; j < blocks_left; j++) {
                lud_perimeter(m, matrix_dim, offset);
            }

            // 3. lud_internal for internal blocks
            #pragma omp parallel for collapse(2) schedule(static)
            for (int by = 0; by < blocks_left; by++) {
                for (int bx = 0; bx < blocks_left; bx++) {
                    lud_internal(m, matrix_dim, offset, bx, by);
                }
            }
        }
    }
}
